import { useState, useEffect } from "react";
import { getTasks, createTask, updateTask, deleteTask } from "../services/api";

export function useTasks() {
  const [tasks,   setTasks]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [error,   setError]   = useState(null);

  const fetchTasks = async () => {
    try {
      setLoading(true);
      setError(null);
      const res = await getTasks();
      setTasks(res.data.data);
    } catch (err) {
      setError("Failed to load tasks. Is the backend running?");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchTasks(); }, []);

  const addTask = async (form) => {
    try {
      const res = await createTask(form);
      setTasks(t => [...t, res.data.data]);
    } catch (err) {
      setError("Failed to create task.");
    }
  };

  const editTask = async (id, form) => {
    try {
      const res = await updateTask(id, form);
      setTasks(t => t.map(tk => tk.id === id ? res.data.data : tk));
    } catch (err) {
      setError("Failed to update task.");
    }
  };

  const removeTask = async (id) => {
    try {
      await deleteTask(id);
      setTasks(t => t.filter(tk => tk.id !== id));
    } catch (err) {
      setError("Failed to delete task.");
    }
  };

  return { tasks, loading, error, addTask, editTask, removeTask };
}
